// ════════ API CONFIGURATION ════════
const API_HOST = window.location.hostname === 'localhost' ? 'localhost:5000' : `${window.location.hostname}:5000`;
const API_BASE = `http://${API_HOST}/api`;

// ════════ GOOGLE AUTH INITIALIZATION ════════
function initGoogleAuth() {
  if (typeof google === 'undefined') {
    console.warn('GSI Script not loaded yet. Retrying...');
    setTimeout(initGoogleAuth, 1000);
    return;
  }

  google.accounts.id.initialize({
    client_id: "990682432689-lumtdtk3t979kqkbv88p81pq1riptlo7.apps.googleusercontent.com",
    callback: handleGoogleCredentialResponse
  });

  const containers = document.querySelectorAll('.google-login-btn-container');
  containers.forEach(container => {
    google.accounts.id.renderButton(container, {
      theme: 'outline',
      size: 'large',
      width: container.parentElement.offsetWidth || 280
    });
  });

  console.log('Google Auth Initialized (HR)');
}

async function handleGoogleCredentialResponse(response) {
  showToast('Authenticating with Google...');
  try {
    const res = await fetch(`${API_BASE}/auth/google-login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ credential: response.credential, role: 'hr' })
    });

    if (!res.ok) {
      const errData = await res.json().catch(() => ({}));
      throw new Error(errData.message || `Server error: ${res.status}`);
    }

    const result = await res.json();
    if (result.success) {
      localStorage.setItem('sk_token', result.data.token);
      _handleHRGoogleLoginSuccess(result.data.user);
    } else {
      showToast(result.message || 'Verification failed');
    }
  } catch (e) {
    console.error('Auth Connection Error:', e);
    showToast('Login Failed: ' + e.message);
    if (e.message.toLowerCase().includes('failed to fetch')) {
      alert('Backend connection failed! Ensure your API server is running at http://localhost:5000');
    }
  }
}

// Start initialization
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', initGoogleAuth);
} else {
  initGoogleAuth();
}

// ════════ RECRUITER AUTH HANDLERS ════════
function toggleHRAuth(isSignup) {
  const loginView = document.getElementById('hr-login-view');
  const signupView = document.getElementById('hr-signup-view');
  if (isSignup) {
    loginView.style.display = 'none';
    signupView.style.display = 'block';
  } else {
    loginView.style.display = 'block';
    signupView.style.display = 'none';
  }
}

async function doHRPortalRegister() {
  const name = document.getElementById('hr-reg-name').value.trim();
  const email = document.getElementById('hr-reg-email').value.trim();
  const company = document.getElementById('hr-reg-company').value.trim();
  const password = document.getElementById('hr-reg-pass').value.trim();
  const errEl = document.getElementById('hr-reg-err');

  if (!name || !email || !company || !password) {
    errEl.textContent = 'All fields are required';
    errEl.style.display = 'block';
    return;
  }

  try {
    const res = await fetch(`${API_BASE}/auth/register`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name, email, company, password, role: 'recruiter' })
    });

    const result = await res.json();
    if (result.success) {
      localStorage.setItem('sk_token', result.data.token);
      showToast('Account created successfully! Welcome to Skillovate.');
      _handleHRGoogleLoginSuccess(result.data.user);
    } else {
      errEl.textContent = result.message || 'Registration failed';
      errEl.style.display = 'block';
    }
  } catch (e) {
    console.error('Registration Error:', e);
    showToast('Connection failed');
  }
}

async function doHRForgotPassword() {
  const email = document.getElementById('hr-login-email').value.trim();
  if (!email) {
    showToast('Please enter your email first');
    return;
  }

  showToast('Processing request...');
  try {
    const res = await fetch(`${API_BASE}/auth/forgot-password`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ email })
    });
    const result = await res.json();
    if (result.success) {
      alert('Password reset link has been sent to ' + email);
    } else {
      showToast(result.message || 'Recovery failed');
    }
  } catch (e) {
    showToast('Recovery connection failed');
  }
}

// ════════ HR VACANCY POST ════════
async function postVacancyLive(btn){
  const card = btn.closest('.card');
  const inputs = card.querySelectorAll('.input-field');
  const title    = inputs[0]?.value?.trim() || 'Software Engineer';
  const roleType = inputs[1]?.value || 'Full-time';
  const deadline = inputs[2]?.value || '';
  const minScore = inputs[4]?.value || '';
  const gradYear = inputs[5]?.value || 'Any year';
  const desc     = inputs[6]?.value?.trim() || '';
  const hrName   = document.getElementById('uname')?.textContent || 'HR';
  const company  = document.getElementById('urole')?.textContent?.replace('Recruiter · ','') || 'Company';

  if(!title){ showToast('Please enter a job title'); return; }

  const result = await apiPost('/hr/vacancies',{
    company, role:title, description:desc,
    skills:['Quantitative','Logical Reasoning'],
    location:'India', salary:'As per industry standards',
    posted_by: hrName
  });

  showToast('Vacancy posted! Students can now apply.');
  // Clear fields
  inputs.forEach(inp=>{ if(inp.tagName==='INPUT'||inp.tagName==='TEXTAREA') inp.value=''; });
}

// ════════ AI PROFILE SUMMARY (Gemini/BerthAI) ════════
async function generateAIProfileSummary(){
  const name   = currentUser.name || document.getElementById('uname')?.textContent || 'Student';
  const container = document.getElementById('profile-ai-summary');
  if(!container) return;

  container.textContent = 'Generating AI summary...';
  container.style.fontStyle = 'italic';
  container.style.color = 'var(--muted)';

  const acc = currentUser.avgAccuracy;
  const streak = currentUser.streak;
  const rank = currentUser.nationalRank ? 'top '+Math.round(currentUser.nationalRank/10)+'%' : null;

  try{
    let summary;
    if(swAIMode){
      const data = await apiPost('/ai/summary',{
        subject:'general', score: acc||0, accuracy:(acc||0)/100,
        time_taken:0, user_name:name
      });
      summary = data?.summary;
    } else {
      const traits = [
        acc ? `${acc}% avg accuracy` : null,
        streak > 0 ? `${streak}-day streak` : null,
        rank ? `ranked in the ${rank} nationally` : null,
        currentUser.testsCompleted > 0 ? `${currentUser.testsCompleted} sessions completed` : null,
      ].filter(Boolean).join(', ');
      const prompt = `Write a 2-sentence professional aptitude profile for ${name}. They have: ${traits||'just started their aptitude journey'}. Third person, professional tone, plain text only.`;
      const res = await fetch(SKILLY_API_URL,{
        method:'POST', headers:{'Content-Type':'application/json'},
        body: JSON.stringify({ model: 'phi3', prompt: prompt, stream: false })
      });
      const data = await res.json();
      summary = data.response?.trim();
      apiPost('/ai/summary',{ subject:'profile', score:acc||0, accuracy:(acc||0)/100, time_taken:0 });
    }
    if(summary){
      container.textContent = summary;
      container.style.fontStyle = 'normal';
      container.style.color = 'var(--text)';
    }
  }catch(e){
    const fallback = currentUser.testsCompleted > 0
      ? `${name} demonstrates consistent aptitude practice with ${acc||0}% average accuracy across ${currentUser.testsCompleted} sessions.${rank ? ' Ranked in the '+rank+' nationally.' : ''}`
      : `${name} has just started their aptitude journey on SkilloWait. Complete practice sessions to generate a full AI profile.`;
    container.textContent = fallback;
    container.style.fontStyle='normal';
    container.style.color='var(--text)';
  }
}

// ════════ BILLING ════════
function setBilling(c){
  state.billing=c;
  document.getElementById('bt-m').classList.toggle('on',c==='m');
  document.getElementById('bt-y').classList.toggle('on',c==='y');
  document.getElementById('billing-save').style.display=c==='y'?'block':'none';
  document.getElementById('pro-price').textContent=c==='y'?'3,100':'299';
  document.getElementById('pro-period').textContent=c==='y'?'per year · ₹258/month equivalent':'per month · billed monthly';
}


